library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;

entity top is
  port (
    a : out character
  );
end entity;

architecture rtl of top is
component sub is
  generic (
    s : character
  );
  port (
    a : out character
  );
end component;
begin
  sub_i: sub
    generic map (
        s => '1'
    )
    port map (
        a => a
    );
end architecture;

entity sub is
  generic (
    s : character := 'a'
  );
  port (
    a : out character
  );
end entity;

architecture rtl of sub is
begin
  a <= s;
end architecture;
